import { Drawer, List, ListItemButton, ListItemText } from "@mui/material";
import { useNavigate } from "react-router-dom";

export default function Sidebar() {
  const navigate = useNavigate();
  const role = localStorage.getItem("role"); // 🔥 get role

  // ✅ Role-based menus
  const menu = {
    superadmin: [
      { name: "Dashboard", path: "/superadmin" },
      { name: "Create Admin", path: "/superadmin/create-admin" },
    ],
    admin: [
      { name: "Dashboard", path: "/admin" },
      { name: "Projects", path: "/admin/projects" },
      { name: "Users", path: "/admin/users" },
    ],
    member: [
      { name: "Dashboard", path: "/member" },
      { name: "Assign Roles", path: "/member/roles" },
    ],
    user: [{ name: "Dashboard", path: "/user" }],
  };

  return (
    <Drawer
      variant="permanent"
      sx={{
        width: 220,
        flexShrink: 0,
        "& .MuiDrawer-paper": {
          width: 220,
          boxSizing: "border-box",
        },
      }}
    >
      <List sx={{ width: 220 }}>
        {menu[role]?.map((item) => (
          <ListItemButton key={item.name} onClick={() => navigate(item.path)}>
            <ListItemText primary={item.name} />
          </ListItemButton>
        ))}
      </List>
    </Drawer>
  );
}
